        let line = raw.trim_start();
        for prefix in ["export const ", "export function "] {
            if let Some(rest) = line.strip_prefix(prefix) {
                let symbol: String = rest
                    .chars()
                    .take_while(|c| c.is_ascii_alphanumeric() || *c == '_')
