pub fn mote_e(a: &mut State, b: &str, c: bool) -> Observation {
    if let Some(entry) = a.entries.iter().find(|entry| entry.symbol == b) {
        let reused = a.last_seen.get(b).map(|old| *old == entry.handle).unwrap_or(false);
